+<body>
+  <main class="shell">
+    <div class="content">
+      <section class="game-pane">
+        <div class="eyebrow">Arcade Mode</div>
+        <h1>Snake</h1>
+        <p class="subtitle">Eat, grow, and avoid crashing into yourself.</p>
+
+        <div class="statusbar">
+          <div class="stat">
+            <span class="label">Score</span>
+            <span class="value" id="score">0</span>
+          </div>
+          <div class="stat">
+            <span class="label">Best</span>
+            <span class="value" id="best">0</span>
+          </div>
+          <div class="stat">
+            <span class="label">State</span>
+            <span class="value" id="state">Ready</span>
+          </div>
+        </div>
+
+        <div class="board-wrap">
+          <canvas id="game" width="600" height="600" aria-label="Snake game board"></canvas>
+          <div class="overlay" id="overlay">
+            <div class="overlay-card">
+              <h2 id="overlay-title">Ready to play?</h2>
+              <p id="overlay-text">Use the arrow keys to start moving. Press restart anytime for a fresh run.</p>
+              <button id="overlay-button" type="button">Start Game</button>
+            </div>
+          </div>
+        </div>
+      </section>
+
+      <aside class="info-pane">
+        <div class="card">
+          <h3>Controls</h3>
+          <p>Use the arrow keys to steer. Press <strong>Space</strong> or the restart button after a loss.</p>
+          <div class="controls" aria-hidden="true">
+            <div class="spacer key">.</div>
+            <div class="key">↑</div>
+            <div class="spacer key">.</div>
+            <div class="key">←</div>
+            <div class="key">↓</div>
+            <div class="key">→</div>
+          </div>
+        </div>
+
+        <div class="card">
+          <h3>How scoring works</h3>
+          <p>Each apple is worth 10 points. The pace increases as the snake grows, so longer runs get tougher.</p>
+        </div>
+
+        <div class="card">
+          <h3>Game Status</h3>
+          <p class="status" id="status">Press an arrow key or click start.</p>
+          <div class="action-row">
+            <button id="restart" type="button">Restart</button>
+          </div>
+        </div>
+      </aside>
+    </div>
+  </main>
+
+  <script>
+    const canvas = document.getElementById("game");
+    const ctx = canvas.getContext("2d");
+    const scoreEl = document.getElementById("score");
+    const bestEl = document.getElementById("best");
+    const stateEl = document.getElementById("state");
+    const statusEl = document.getElementById("status");
+    const restartButton = document.getElementById("restart");
+    const overlay = document.getElementById("overlay");
+    const overlayTitle = document.getElementById("overlay-title");
+    const overlayText = document.getElementById("overlay-text");
+    const overlayButton = document.getElementById("overlay-button");
+
+    const gridSize = 20;
+    const tileCount = 20;
+    const tileSize = canvas.width / tileCount;
+    const storageKey = "snake-best-score";
+    const directions = {
+      ArrowUp: { x: 0, y: -1 },
+      ArrowDown: { x: 0, y: 1 },
+      ArrowLeft: { x: -1, y: 0 },
+      ArrowRight: { x: 1, y: 0 }
+    };
+
+    let snake;
+    let direction;
+    let pendingDirection;
+    let food;
+    let score;
+    let bestScore = Number(localStorage.getItem(storageKey) || 0);
+    let gameOver;
+    let started;
+    let lastTick = 0;
+
+    bestEl.textContent = String(bestScore);
+
+    function resetGame() {
+      snake = [
+        { x: 10, y: 10 },
+        { x: 9, y: 10 },
+        { x: 8, y: 10 }
+      ];
+      direction = { x: 1, y: 0 };
+      pendingDirection = direction;
+      food = spawnFood();
+      score = 0;
+      gameOver = false;
+      started = false;
+      lastTick = 0;
+      updateScore();
+      updateState("Ready", "Press an arrow key or click start.");
+      showOverlay("Ready to play?", "Use the arrow keys to start moving. Press restart anytime for a fresh run.", "Start Game");
+      draw();
+    }
+
+    function spawnFood() {
+      let candidate;
+      do {
+        candidate = {
+          x: Math.floor(Math.random() * tileCount),
+          y: Math.floor(Math.random() * tileCount)
+        };
+      } while (snake && snake.some((segment) => segment.x === candidate.x && segment.y === candidate.y));
+      return candidate;
+    }
+
+    function updateScore() {
+      scoreEl.textContent = String(score);
+      if (score > bestScore) {
+        bestScore = score;
+        localStorage.setItem(storageKey, String(bestScore));
+        bestEl.textContent = String(bestScore);
+      }
+    }
+
+    function updateState(label, message, isGameOver = false) {
+      stateEl.textContent = label;
+      statusEl.textContent = message;
+      statusEl.classList.toggle("game-over", isGameOver);
+    }
+
+    function showOverlay(title, text, buttonText) {
+      overlayTitle.textContent = title;
+      overlayText.textContent = text;
+      overlayButton.textContent = buttonText;
+      overlay.classList.remove("hidden");
+    }
+
+    function hideOverlay() {
+      overlay.classList.add("hidden");
+    }
+
+    function setDirection(next) {
+      if (gameOver) {
+        return;
+      }
+
+      const reversing = next.x === -direction.x && next.y === -direction.y;
+      if (reversing) {
+        return;
+      }
+
+      pendingDirection = next;
+
+      if (!started) {
+        started = true;
+        hideOverlay();
+        updateState("Running", "Collect apples and avoid your tail.");
+      }
+    }
+
+    function tick() {
+      direction = pendingDirection;
+      const head = { x: snake[0].x + direction.x, y: snake[0].y + direction.y };
+
+      if (
+        head.x < 0 ||
+        head.x >= tileCount ||
+        head.y < 0 ||
+        head.y >= tileCount ||
+        snake.some((segment) => segment.x === head.x && segment.y === head.y)
+      ) {
+        gameOver = true;
+        updateState("Game Over", `Final score: ${score}. Press Space or Restart to play again.`, true);
+        showOverlay("Game Over", `You scored ${score} point${score === 1 ? "" : "s"}. Try again for a longer run.`, "Play Again");
+        draw();
+        return;
+      }
+
+      snake.unshift(head);
+
+      if (head.x === food.x && head.y === food.y) {
+        score += 10;
+        updateScore();
+        food = spawnFood();
+        updateState("Running", "Nice catch. Keep going.");
+      } else {
+        snake.pop();
+      }
+
+      draw();
+    }
+
+    function getSpeed() {
+      const base = 150;
+      return Math.max(70, base - (snake.length - 3) * 3);
+    }
+
+    function drawRoundedTile(x, y, color, inset = 2, radius = 10) {
+      const px = x * tileSize + inset;
+      const py = y * tileSize + inset;
+      const size = tileSize - inset * 2;
+      ctx.fillStyle = color;
+      ctx.beginPath();
+      ctx.roundRect(px, py, size, size, radius);
+      ctx.fill();
+    }
+
+    function draw() {
+      ctx.clearRect(0, 0, canvas.width, canvas.height);
+
+      ctx.fillStyle = "rgba(255,255,255,0.02)";
+      for (let i = 0; i < tileCount; i += 1) {
+        for (let j = 0; j < tileCount; j += 1) {
+          if ((i + j) % 2 === 0) {
+            ctx.fillRect(i * tileSize, j * tileSize, tileSize, tileSize);
+          }
+        }
+      }
+
+      const foodGlow = ctx.createRadialGradient(
+        food.x * tileSize + tileSize / 2,
+        food.y * tileSize + tileSize / 2,
+        2,
+        food.x * tileSize + tileSize / 2,
+        food.y * tileSize + tileSize / 2,
+        tileSize / 1.3
+      );
+      foodGlow.addColorStop(0, "rgba(255, 201, 92, 0.9)");
+      foodGlow.addColorStop(1, "rgba(255, 101, 119, 0.06)");
+      drawRoundedTile(food.x, food.y, foodGlow, 4, 999);
+      drawRoundedTile(food.x, food.y, "#ff8b5e", 8, 999);
+
+      snake.forEach((segment, index) => {
+        if (index === 0) {
+          const headGradient = ctx.createLinearGradient(
+            segment.x * tileSize,
+            segment.y * tileSize,
+            segment.x * tileSize + tileSize,
+            segment.y * tileSize + tileSize
+          );
+          headGradient.addColorStop(0, "#9af7c8");
+          headGradient.addColorStop(1, "#39c8ff");
+          drawRoundedTile(segment.x, segment.y, headGradient, 3, 12);
+
+          const eyeOffsetX = direction.x !== 0 ? (direction.x > 0 ? 17 : 9) : 10;
+          const eyeOffsetYTop = direction.y > 0 ? 16 : 10;
+          const eyeOffsetYBottom = direction.y > 0 ? 16 : 10;
+          ctx.fillStyle = "#031019";
+          ctx.beginPath();
+          ctx.arc(segment.x * tileSize + eyeOffsetX, segment.y * tileSize + eyeOffsetYTop, 2.2, 0, Math.PI * 2);
+          ctx.arc(segment.x * tileSize + (direction.x !== 0 ? eyeOffsetX : 20), segment.y * tileSize + (direction.y !== 0 ? eyeOffsetYBottom : 20), 2.2, 0, Math.PI * 2);
+          ctx.fill();
+        } else {
+          const alpha = Math.max(0.32, 0.9 - index * 0.045);
+          drawRoundedTile(segment.x, segment.y, `rgba(102, 240, 169, ${alpha})`, 4, 10);
+        }
+      });
+    }
+
+    function gameLoop(timestamp) {
+      if (started && !gameOver) {
+        if (!lastTick || timestamp - lastTick >= getSpeed()) {
+          tick();
+          lastTick = timestamp;
+        }
+      }
+      requestAnimationFrame(gameLoop);
+    }
+
+    document.addEventListener("keydown", (event) => {
+      if (event.code === "Space") {
+        if (gameOver) {
+          resetGame();
+        }
+        return;
+      }
+
+      const next = directions[event.key];
+      if (!next) {
+        return;
+      }
+
+      event.preventDefault();
+      setDirection(next);
+    });
+
+    restartButton.addEventListener("click", resetGame);
+    overlayButton.addEventListener("click", () => {
+      if (gameOver) {
+        resetGame();
+        return;
+      }
+
+      started = true;
+      hideOverlay();
+      updateState("Running", "Collect apples and avoid your tail.");
+    });
+
+    resetGame();
+    requestAnimationFrame(gameLoop);
+  </script>
+</body>
+</html>
*** End Patch

