+        for (let j = 0; j < tileCount; j += 1) {
+          if ((i + j) % 2 === 0) {
+            ctx.fillRect(i * tileSize, j * tileSize, tileSize, tileSize);
+          }
+        }
+      }
+
+      const foodGlow = ctx.createRadialGradient(
+        food.x * tileSize + tileSize / 2,
+        food.y * tileSize + tileSize / 2,
+        2,
+        food.x * tileSize + tileSize / 2,
+        food.y * tileSize + tileSize / 2,
+        tileSize / 1.3
+      );
+      foodGlow.addColorStop(0, "rgba(255, 201, 92, 0.9)");
+      foodGlow.addColorStop(1, "rgba(255, 101, 119, 0.06)");
+      drawRoundedTile(food.x, food.y, foodGlow, 4, 999);
+      drawRoundedTile(food.x, food.y, "#ff8b5e", 8, 999);
+
+      snake.forEach((segment, index) => {
+        if (index === 0) {
+          const headGradient = ctx.createLinearGradient(
+            segment.x * tileSize,
+            segment.y * tileSize,
+            segment.x * tileSize + tileSize,
+            segment.y * tileSize + tileSize
+          );
+          headGradient.addColorStop(0, "#9af7c8");
+          headGradient.addColorStop(1, "#39c8ff");
+          drawRoundedTile(segment.x, segment.y, headGradient, 3, 12);
+
+          const eyeOffsetX = direction.x !== 0 ? (direction.x > 0 ? 17 : 9) : 10;
+          const eyeOffsetYTop = direction.y > 0 ? 16 : 10;
+          const eyeOffsetYBottom = direction.y > 0 ? 16 : 10;
+          ctx.fillStyle = "#031019";
+          ctx.beginPath();
+          ctx.arc(segment.x * tileSize + eyeOffsetX, segment.y * tileSize + eyeOffsetYTop, 2.2, 0, Math.PI * 2);
